export async function getStateSummary(
	client: Client,
	now = Date.now(),
): Promise<StateSummary> {
	const [
		runCountsResult,
		attemptCountsResult,
		activeClaimsResult,
		recentEventsResult,
	] = await Promise.all([
		client.execute(`
			SELECT status, COUNT(*) AS count
			FROM runs
			GROUP BY status
			ORDER BY status ASC
		`),
		client.execute(`
			SELECT status, COUNT(*) AS count
			FROM attempts
			GROUP BY status
			ORDER BY status ASC
		`),
		client.execute({
			sql: `
				SELECT COUNT(*) AS count
				FROM claims
				WHERE claim_expires_at > ?
			`,
			args: [now],
		}),
		client.execute(`
			SELECT
				id,
				run_id,
				attempt_id,
				level,
				type,
				message,
				data_json,
				created_at
			FROM events
			ORDER BY created_at DESC
			LIMIT 20
		`),
	]);

	return {
		runStatusCounts: mapCountRows(runCountsResult.rows),
		attemptStatusCounts: mapCountRows(attemptCountsResult.rows),
		activeClaimCount: getNumber(activeClaimsResult.rows[0], "count"),
		recentEvents: recentEventsResult.rows.map(mapEventRow),
	};
}

